export type RecommendationContractTimingAuthority =
  | "shape_only"
  | "may_lead"
  | "must_not_lead";

export type RecommendationContractExpectation = {
  categorySelectionMode: "explicit_category" | "surprise_me_open_preference";
  expectedCategory?: string;
  resolvedCategory?: string;
  expectedFocusBehavior: string;
  expectedCapacityBehavior: string;
  expectedAudienceBehavior: string;
  timingAuthority: RecommendationContractTimingAuthority;
  acceptablePatternKeys?: string[];
  acceptableRitualFormFamilies?: string[];
  disallowedPatternKeys?: string[];
  disallowedRitualFormFamilies?: string[];
  disallowedNormalCopyPhrases?: string[];
  requiredExplanationTerms?: string[];
  expectedWarningIds?: string[];
  coverageGapExpected?: boolean;
  closestCompatiblePatternExpected?: boolean;
  rationale: string;
};

export type RecommendationQualityScenario = {
  id: string;
  title: string;
  purpose: string;
  currentDate: string;
  currentRitualCheckIn: CurrentRitualCheckIn;
  profilePlaceholders?: PrivateProfileSignalInput[];
  contract?: RecommendationContractExpectation;
  expectedQualities: string[];
  disallowedOutcomes: string[];
  humanReviewNotes: string;
  input: GenerateWeeklyBriefInput;
};

